import{_ as r,o as t,c as o,ae as n}from"./chunks/framework.C23mN02-.js";const p=JSON.parse('{"title":"《史记》典故","description":"","frontmatter":{},"headers":[],"relativePath":"sucai/shi/史记.md","filePath":"sucai/shi/史记.md"}'),s={name:"sucai/shi/史记.md"};function e(g,a,i,h,l,d){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="《史记》典故" tabindex="-1">《史记》典故 <a class="header-anchor" href="#《史记》典故" aria-label="Permalink to &quot;《史记》典故&quot;">​</a></h1><h2 id="纸上谈兵" tabindex="-1">纸上谈兵 <a class="header-anchor" href="#纸上谈兵" aria-label="Permalink to &quot;纸上谈兵&quot;">​</a></h2><p><strong>典故：</strong> 赵括年轻时学习兵法，谈起兵事头头是道，连父亲赵奢都难不倒他。然而他只会夸夸其谈，缺乏实战经验。长平之战中，赵括担任赵军主帅，盲目出击，结果大败，四十万赵军被坑杀。 <strong>出处：</strong> 《史记·廉颇蔺相如列传》 <strong>释义：</strong> 在纸面上谈论用兵策略。比喻空谈理论，不能解决实际问题。</p><h2 id="破釜沉舟" tabindex="-1">破釜沉舟 <a class="header-anchor" href="#破釜沉舟" aria-label="Permalink to &quot;破釜沉舟&quot;">​</a></h2><p><strong>典故：</strong> 巨鹿之战中，项羽率楚军渡过黄河后，下令砸碎全部炊具，烧毁营舍，每人只带三天口粮，表示决心拼死一战，没有退路。 <strong>出处：</strong> 《史记·项羽本纪》 <strong>释义：</strong> 砸碎锅子，凿沉船只。比喻下定决心，不留退路。</p><h2 id="背水一战" tabindex="-1">背水一战 <a class="header-anchor" href="#背水一战" aria-label="Permalink to &quot;背水一战&quot;">​</a></h2><p><strong>典故：</strong> 韩信率军攻打赵国，在井陉口列阵，背靠河水布阵，使士兵绝境中拼死作战，大败赵军。 <strong>出处：</strong> 《史记·淮阴侯列传》 <strong>释义：</strong> 背向江河布阵拼死一战。比喻在绝境中决一死战。</p><h2 id="草木皆兵" tabindex="-1">草木皆兵 <a class="header-anchor" href="#草木皆兵" aria-label="Permalink to &quot;草木皆兵&quot;">​</a></h2><p><strong>典故：</strong> 淝水之战中，前秦苻坚在寿阳城上望见晋军阵容整齐，再看八公山上的草木，以为都是晋兵，心中恐惧。 <strong>出处：</strong> 《晋书·苻坚载记》 <strong>释义：</strong> 把山上的草木都当成敌兵。形容人在极度惊恐时，一点风吹草动都会疑神疑鬼。</p><h2 id="卧薪尝胆" tabindex="-1">卧薪尝胆 <a class="header-anchor" href="#卧薪尝胆" aria-label="Permalink to &quot;卧薪尝胆&quot;">​</a></h2><p><strong>典故：</strong> 越王勾践战败后被吴国俘虏，归国后睡柴草、尝苦胆，不忘复仇。最终灭掉吴国。 <strong>出处：</strong> 《史记·越王勾践世家》 <strong>释义：</strong> 睡在柴草上，尝尝苦胆。形容人刻苦自励，发愤图强。</p><h2 id="完壁归赵" tabindex="-1">完壁归赵 <a class="header-anchor" href="#完壁归赵" aria-label="Permalink to &quot;完壁归赵&quot;">​</a></h2><p><strong>典故：</strong> 蔺相如奉命携和氏璧入秦，见秦王无意偿赵城，乃以策略令秦王斋戒受璧，使完璧归赵。 <strong>出处：</strong> 《史记·廉颇蔺相如列传》 <strong>释义：</strong> 把完好无损的玉璧送回赵国。比喻把原物完好无损地归还原主。</p><h2 id="霸王别姬" tabindex="-1">霸王别姬 <a class="header-anchor" href="#霸王别姬" aria-label="Permalink to &quot;霸王别姬&quot;">​</a></h2><p><strong>典故：</strong> 项羽被困垓下，夜闻四面楚歌，知道大势已去，与虞姬慷慨悲歌，诀别后突围乌江。 <strong>出处：</strong> 《史记·项羽本纪》 <strong>释义：</strong> 英雄末路的悲壮告别。后常指美人迟暮或英雄末路。</p><h2 id="封金挂印" tabindex="-1">封金挂印 <a class="header-anchor" href="#封金挂印" aria-label="Permalink to &quot;封金挂印&quot;">​</a></h2><p><strong>典故：</strong> 关羽得知刘备在袁绍处，即封存曹操所赐金银财宝和汉寿亭侯官印，归还曹操，投奔刘备。 <strong>出处：</strong> 《三国志·蜀书·关羽传》 <strong>释义：</strong> 封存金银，挂起官印。形容不为利禄动心，义气深重。</p><h2 id="暗渡陈仓" tabindex="-1">暗渡陈仓 <a class="header-anchor" href="#暗渡陈仓" aria-label="Permalink to &quot;暗渡陈仓&quot;">​</a></h2><p><strong>典故：</strong> 韩信表面上修筑栈道吸引敌军注意力，暗中绕道偷袭陈仓，一举平定三秦。 <strong>出处：</strong> 《史记·淮阴侯列传》 <strong>释义：</strong> 正面佯修栈道，暗中绕道偷袭。比喻用假象迷惑对方以达到目的。</p><h2 id="田忌赛马" tabindex="-1">田忌赛马 <a class="header-anchor" href="#田忌赛马" aria-label="Permalink to &quot;田忌赛马&quot;">​</a></h2><p><strong>典故：</strong> 战国时田忌与齐王赛马，用孙膑计策，以上马对中马、中马对下马、下马对上马，赢得比赛。 <strong>出处：</strong> 《史记·孙子吴起列传》 <strong>释义：</strong> 运用策略以弱胜强。比喻在竞赛中智取对手。</p>',21)])])}const u=r(s,[["render",e]]);export{p as __pageData,u as default};
